import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

// 나쁜 코드 스니펫: 경로 조작(Path Traversal) 취약점
public class BadServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws ServletException, IOException {
        // 사용자 입력을 직접 사용하여 파일 경로 생성
        String filename = request.getParameter("file");

        // 취약점: 사용자 입력을 검증하지 않고 직접 파일 경로에 사용
        // 이로 인해 공격자가 ../../etc/passwd 와 같은 경로를 입력하여
        // 서버의 민감한 파일에 접근할 수 있습니다.
        File file = new File("/var/www/uploads/" + filename);

        if (file.exists()) {
            FileInputStream fis = new FileInputStream(file);
            response.setContentType("application/octet-stream");
            response.setHeader("Content-Disposition", "attachment; filename=\"" + filename + "\"");
            fis.transferTo(response.getOutputStream());
            fis.close();
        }
    }
}

***

// 좋은 코드 스니펫: 경로 조작 취약점 방지
public class GoodServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws ServletException, IOException {
        String filename = request.getParameter("file");

        // 안전한 파일 이름 검증: 특수 문자 제거 및 기본 경로 외 접근 차단
        if (filename == null || !filename.matches("[a-zA-Z0-9._-]+")) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid filename");
            return;
        }

        // 절대 경로 생성
        File baseDir = new File("/var/www/uploads");
        File file = new File(baseDir, filename);

        // 파일이 기본 디렉토리 내에 있는지 확인 (Path Traversal 방지)
        if (!file.getCanonicalPath().startsWith(baseDir.getCanonicalPath())) {
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access denied");
            return;
        }

        if (file.exists() && file.isFile()) {
            FileInputStream fis = new FileInputStream(file);
            response.setContentType("application/octet-stream");
            // 파일 이름은 서버에서 정의된 안전한 이름만 사용
            response.setHeader("Content-Disposition", "attachment; filename=\"safe_file.dat\"");
            fis.transferTo(response.getOutputStream());
            fis.close();
        } else {
            response.sendError(HttpServletResponse.SC_NOT_FOUND, "File not found");
        }
    }
}
